    pub rlimits: Vec<usize>,               // 资源限制
    pub sigaction: [SigAction; 65],        // 信号处理动作
    pub futex_table: Arc<Mutex<FutexTable>>, // Futex 表
    pub shms: Vec<MapedSharedMemory>,      // 共享内存映射
