    child_tid: UserRef<i32>,
) -> SysResult {
    let flags = CloneFlags::from_bits_truncate(clone_flags as _);
    let new_task = UserTask::new(Arc::downgrade(&self.task), &self.task.pcb.lock().curr_dir.path().unwrap());

